     2→import type { DisplayMessage, DisplayItem } from "../api.js";
     3→import {
     4→  formatDuration,
     5→  formatTokens,
     6→  truncate,
     7→  roleColor,
     8→  roleIcon,
     9→  formatJson,
    10→  renderMarkdown,
    11→} from "../lib/format.js";
    12→import { colors, getItemColor, getTeamColor } from "../lib/theme.js";
    13→import { getItemIcon, getItemName, getItemSummary } from "../lib/items.js";
    14→import { StatsBar, statsFromMessage } from "./StatsBar.js";
    15→import { BrailleSpinner, OngoingDot } from "./OngoingDots.js";
    16→import { stableWindow } from "../lib/window.js";
    17→import {
    18→  IconExpanded,
    19→  IconCollapsed,
    20→  IconBarSingle,
    21→  IconBarDouble,
    22→  IconSelected2,
    23→  IconHRule,
    24→} from "../lib/icons.js";
    25→
    26→/** Max content width — matches Go TUI's maxContentWidth. */
    27→const MAX_CONTENT_WIDTH = 160;
    28→
    29→/** Limit text to maxLines while preserving newlines. Appends "…" if truncated. */
    30→function limitLines(text: string, maxLines: number): string {
    31→  const lines = text.split("\n");
    32→  if (lines.length <= maxLines) return text;
    33→  return lines.slice(0, maxLines).join("\n") + "\n…(" + (lines.length - maxLines) + " more lines)";
    34→}
    35→
    36→/** Clamp each line to maxWidth so bordered boxes don't overflow the terminal. */
    37→function clampLines(text: string, maxWidth: number): string {
    38→  return text
    39→    .split("\n")
    40→    .map((line) => (line.length > maxWidth ? line.slice(0, maxWidth - 1) + "…" : line))
    41→    .join("\n");
    42→}
    43→
    44→interface DetailViewProps {
    45→  message: DisplayMessage;
    46→  selectedItem: number;
    47→  expandedItems: Set<number>;
    48→  ongoing: boolean;
    49→  depth?: number;
    50→}
    51→
    52→function itemBorderColor(item: DisplayItem, isSelected: boolean): string {
    53→  if (isSelected) return colors.accent;
    54→  // Subagent items with messages get their team color
    55→  if (item.subagent_messages.length > 0 && item.team_color) {
    56→    return getTeamColor(item.team_color);
    57→  }
    58→  return getItemColor(item.item_type, !!item.tool_error);
