                {formatJson(item.tool_result)}
              </Text>
            </Box>
          )}
        </Box>
      );
    case "Subagent":
      return (
        <Box flexDirection="column" paddingLeft={4}>
          {item.agent_id && (
            <Box gap={1}>
              <Text color={colors.textMuted} bold>
                id:
              </Text>
              <Text dimColor>{item.agent_id}</Text>
            </Box>
          )}
          {item.subagent_desc && (
            <Box gap={1}>
              <Text color={colors.textMuted} bold>
                description:
              </Text>
              <Text wrap="wrap">{item.subagent_desc}</Text>
            </Box>
          )}
          {item.subagent_prompt && (
            <Box flexDirection="column">
              <Text color={colors.textMuted} bold>
                prompt:
              </Text>
              <Text dimColor wrap="wrap">
                {item.subagent_prompt}
              </Text>
            </Box>
          )}
          {item.text && (
            <Box flexDirection="column">
              <Text color={colors.textMuted}>{hrule}</Text>
              <Text bold color={colors.textSecondary}>
                Result:
              </Text>
              <Text wrap="wrap">{item.text}</Text>
            </Box>
          )}
        </Box>
      );
    case "TeammateMessage":
      return (
        <Box flexDirection="column" paddingLeft={4}>
          <Text wrap="wrap">{item.text}</Text>
        </Box>
      );
    case "HookEvent":
      return (
        <Box flexDirection="column" paddingLeft={4}>
          <Box gap={1}>
            <Text color={colors.textMuted} bold>
              hook:
            </Text>
            <Text>
              {item.hook_event}: {item.hook_name}
            </Text>
          </Box>
          {item.hook_command && (
            <Box gap={1}>
              <Text color={colors.textMuted} bold>
                cmd:
              </Text>
              <Text dimColor>{item.hook_command}</Text>
            </Box>
          )}
        </Box>
      );
    default:
      return (
        <Box flexDirection="column" paddingLeft={4}>
          <Text wrap="wrap">{item.text}</Text>
        </Box>
      );
  }
}

