      return (
        <Box flexDirection="column" paddingLeft={4}>
          <Text wrap="truncate">{clamp(formatJson(item.text))}</Text>
        </Box>
      );
    case "ToolCall":
      return (
        <Box flexDirection="column" paddingLeft={4}>
          {item.tool_input && (
            <Box flexDirection="column">
              <Text bold color={colors.textSecondary}>
