                {msg.items.map((item) => (
                  <Box
                    key={`${idx}-${item.item_type}-${item.tool_name || item.agent_id || ""}-${item.duration_ms}`}
                    flexDirection="row"
                  >
                    <Text color={item.team_color ? getTeamColor(item.team_color) : colors.border}>
                      {item.subagent_messages.length > 0 ? IconBarDouble : IconBarSingle}
                    </Text>
