    81→        setPickerLoading(false);
    82→      }
    83→    };
    84→    attempt(10);
    85→    return () => {
    86→      cancelled = true;
    87→      api.unwatchPicker().catch(() => {});
    88→    };
    89→  }, []);
    90→
    91→  useSSE<{ sessions: SessionInfo[] }>(
    92→    "picker-update",
    93→    useCallback((payload) => {
    94→      if (payload.sessions) setAllSessions(payload.sessions);
    95→    }, []),
    96→  );
    97→
    98→  // ---- Session state ----
    99→  const [sessionPath, setSessionPath] = useState("");
   100→  const [messages, setMessages] = useState<DisplayMessage[]>([]);
   101→  const [teams, setTeams] = useState<TeamSnapshot[]>([]);
   102→  const [ongoing, setOngoing] = useState(false);
   103→  const [meta, setMeta] = useState<SessionMeta>(EMPTY_META);
   104→  const [totals, setTotals] = useState<SessionTotals>(EMPTY_TOTALS);
   105→  const [loading, setLoading] = useState(false);
   106→  const [debugEntries, setDebugEntries] = useState<DebugEntry[]>([]);
   107→
   108→  const expandedMessages = useToggleSet();
   109→  const expandedItems = useToggleSet();
   110→
   111→  const [pickerSelected, setPickerSelected] = useState(0);
   112→  const [selectedMessage, setSelectedMessage] = useState(0);
   113→  const [selectedItem, setSelectedItem] = useState(0);
   114→  const [debugSelected, setDebugSelected] = useState(0);
   115→
   116→  // Subagent drill-down: when entering a subagent item, we show its
   117→  // subagent_messages as a message list. The user can then Enter a message
   118→  // to see its items. This mirrors the web's panel stack.
   119→  const [subagentItem, setSubagentItem] = useState<DisplayItem | null>(null);
   120→  const [subagentMsgIdx, setSubagentMsgIdx] = useState(0); // selected message in subagent list
   121→  const [subagentDetailMsg, setSubagentDetailMsg] = useState<DisplayMessage | null>(null); // drilled into a msg
   122→
   123→  const loadSession = useCallback(
   124→    async (path: string) => {
   125→      setLoading(true);
   126→      try {
   127→        const result = await api.loadSession(path);
   128→        setSessionPath(path);
   129→        setMessages(result.messages);
   130→        setTeams(result.teams);
   131→        setOngoing(result.ongoing);
   132→        setMeta(result.meta);
   133→        setTotals(result.session_totals);
   134→        setSelectedMessage(result.messages.length - 1);
   135→        expandedMessages.clear();
   136→        await api.watchSession(path);
   137→      } catch {
   138→        // ignore
   139→      }
   140→      setLoading(false);
   141→    },
   142→    [expandedMessages],
   143→  );
   144→
   145→  useSSE<{
   146→    messages: DisplayMessage[];
   147→    ongoing: boolean;
   148→    permission_mode: string;
   149→    teams: TeamSnapshot[];
   150→    session_totals: SessionTotals;
   151→  }>(
   152→    "session-update",
   153→    useCallback((payload) => {
   154→      setMessages(payload.messages);
   155→      setOngoing(payload.ongoing);
   156→      setTotals(payload.session_totals);
   157→      if (payload.teams) setTeams(payload.teams);
   158→      if (payload.permission_mode) {
   159→        setMeta((m) => ({ ...m, permission_mode: payload.permission_mode }));
   160→      }
   161→    }, []),
   162→  );
   163→
   164→  useEffect(() => {
   165→    return () => {
   166→      api.unwatchSession().catch(() => {});
   167→    };
   168→  }, []);
   169→
   170→  const handleSelectSession = useCallback(
   171→    (s: SessionInfo) => {
   172→      loadSession(s.path);
   173→      setView("list");
   174→      setSidebarFocused(false);
   175→    },
   176→    [loadSession],
   177→  );
   178→
   179→  const handleSelectProject = useCallback((key: string | null) => {
   180→    setSelectedProject(key);
   181→    setSidebarFocused(false);
   182→  }, []);
   183→
   184→  // ---- Single unified keyboard handler ----
   185→  // Use a ref so the useInput effect never re-subscribes.
   186→  // Ink's useInput puts inputHandler in its effect deps — if we pass a
   187→  // new function each render, the stdin listener is removed and re-added
   188→  // on every render, causing keystrokes to be lost in the gap.
   189→  type Key = {
   190→    upArrow: boolean;
   191→    downArrow: boolean;
   192→    leftArrow: boolean;
   193→    rightArrow: boolean;
   194→    return: boolean;
   195→    escape: boolean;
   196→    tab: boolean;
   197→    backspace: boolean;
   198→    delete: boolean;
   199→    ctrl: boolean;
   200→    shift: boolean;
   201→    meta: boolean;
   202→  };
   203→  const inputHandlerRef = useRef<(input: string, key: Key) => void>(() => {});
   204→  inputHandlerRef.current = (input: string, key: Key) => {
   205→    // Sidebar navigation
   206→    if (sidebarFocused && view === "picker") {
   207→      if (input === "j" || key.downArrow) {
   208→        setSidebarHighlight((i) => Math.min(i + 1, projectEntries.length - 1));
   209→      } else if (input === "k" || key.upArrow) {
   210→        setSidebarHighlight((i) => Math.max(i - 1, 0));
   211→      } else if (key.return) {
   212→        const entry = projectEntries[sidebarHighlight];
   213→        if (entry && !entry.isGroup) handleSelectProject(entry.key);
   214→      } else if (input === "l" || key.rightArrow || key.escape) {
   215→        setSidebarFocused(false);
   216→      } else if (input === "q") {
   217→        exit();
   218→      }
   219→      return;
   220→    }
   221→
   222→    switch (view) {
   223→      case "list": {
   224→        if (input === "h" || key.leftArrow) {
   225→          setSidebarFocused(true);
   226→        } else if (input === "j" || key.downArrow) {
   227→          setSelectedMessage((i) => Math.min(i + 1, messages.length - 1));
   228→        } else if (input === "k" || key.upArrow) {
   229→          setSelectedMessage((i) => Math.max(i - 1, 0));
   230→        } else if (input === "G") {
   231→          setSelectedMessage(messages.length - 1);
   232→        } else if (input === "g") {
   233→          setSelectedMessage(0);
   234→        } else if (key.tab) {
   235→          expandedMessages.toggle(selectedMessage);
   236→        } else if (key.return) {
   237→          if (messages.length > 0 && messages[selectedMessage]) {
   238→            setSelectedItem(0);
   239→            expandedItems.clear();
   240→            setSubagentItem(null);
   241→            setSubagentDetailMsg(null);
   242→            setView("detail");
   243→          }
   244→        } else if (input === "e") {
   245→          const indices: number[] = [];
   246→          messages.forEach((m, i) => {
   247→            if (m.role === "claude") indices.push(i);
   248→          });
   249→          expandedMessages.addAll(indices);
   250→        } else if (input === "c") {
   251→          expandedMessages.clear();
   252→        } else if (input === "t") {
   253→          if (teams.length > 0) setView("team");
   254→        } else if (input === "d") {
   255→          if (sessionPath) {
   256→            api
   257→              .getDebugLog(sessionPath)
   258→              .then(setDebugEntries)
   259→              .catch(() => {});
   260→            setDebugSelected(0);
   261→            setView("debug");
   262→          }
   263→        } else if (input === "q" || key.escape) {
   264→          setView("picker");
   265→        }
   266→        break;
   267→      }
   268→      case "detail": {
   269→        if (subagentItem && !subagentDetailMsg) {
   270→          // Viewing subagent message list
   271→          const msgs = subagentItem.subagent_messages;
   272→          if (input === "j" || key.downArrow) {
   273→            setSubagentMsgIdx((i) => Math.min(i + 1, msgs.length - 1));
   274→          } else if (input === "k" || key.upArrow) {
   275→            setSubagentMsgIdx((i) => Math.max(i - 1, 0));
   276→          } else if (key.return) {
   277→            // Enter a message to see its items
   278→            if (msgs[subagentMsgIdx]) {
   279→              setSubagentDetailMsg(msgs[subagentMsgIdx]);
   280→              setSelectedItem(0);
   281→              expandedItems.clear();
   282→            }
   283→          } else if (input === "q" || key.escape) {
   284→            setSubagentItem(null);
   285→            setSubagentMsgIdx(0);
   286→          }
   287→        } else if (subagentDetailMsg) {
   288→          // Viewing items of a subagent message
   289→          const items = subagentDetailMsg.items || [];
   290→          if (input === "j" || key.downArrow) {
   291→            setSelectedItem((i) => Math.min(i + 1, items.length - 1));
   292→          } else if (input === "k" || key.upArrow) {
