   311→            setSubagentMsgIdx(0);
   312→          }
   313→        } else {
   314→          // Top-level detail view (main message items)
   315→          const items = messages[selectedMessage]?.items || [];
   316→          if (input === "j" || key.downArrow) {
   317→            setSelectedItem((i) => Math.min(i + 1, items.length - 1));
   318→          } else if (input === "k" || key.upArrow) {
   319→            setSelectedItem((i) => Math.max(i - 1, 0));
   320→          } else if (key.tab) {
   321→            expandedItems.toggle(selectedItem);
   322→          } else if (key.return) {
   323→            const item = items[selectedItem];
   324→            if (item?.subagent_messages?.length > 0) {
   325→              setSubagentItem(item);
   326→              setSubagentMsgIdx(0);
   327→              setSubagentDetailMsg(null);
   328→            } else {
   329→              expandedItems.toggle(selectedItem);
   330→            }
   331→          } else if (input === "e") {
   332→            expandedItems.addAll(items.map((_it, i) => i));
   333→          } else if (input === "c") {
   334→            expandedItems.clear();
   335→          } else if (input === "q" || key.escape) {
   336→            setView("list");
   337→          }
   338→        }
   339→        break;
   340→      }
   341→      case "debug": {
   342→        if (input === "j" || key.downArrow) {
   343→          setDebugSelected((i) => Math.min(i + 1, debugEntries.length - 1));
   344→        } else if (input === "k" || key.upArrow) {
   345→          setDebugSelected((i) => Math.max(i - 1, 0));
   346→        } else if (input === "q" || key.escape) {
   347→          setView("list");
   348→        }
   349→        break;
   350→      }
   351→      case "team": {
   352→        if (input === "q" || key.escape) setView("list");
   353→        break;
   354→      }
   355→      case "picker": {
   356→        if (input === "h" || key.leftArrow) setSidebarFocused(true);
   357→        else if (input === "j" || key.downArrow) {
   358→          setPickerSelected((i) => Math.min(i + 1, pickerSessions.length - 1));
   359→        } else if (input === "k" || key.upArrow) {
   360→          setPickerSelected((i) => Math.max(i - 1, 0));
   361→        } else if (input === "G") {
   362→          setPickerSelected(pickerSessions.length - 1);
   363→        } else if (input === "g") {
   364→          setPickerSelected(0);
   365→        } else if (key.return) {
   366→          if (pickerSessions[pickerSelected]) {
   367→            handleSelectSession(pickerSessions[pickerSelected]);
   368→          }
   369→        } else if (input === "q") {
   370→          exit();
   371→        }
