import { useState, useEffect, useCallback, useMemo, useRef } from "react";
import { Box, useApp, useInput } from "ink";
import { Spinner } from "@inkjs/ui";
import type {
  SessionInfo,
  DisplayMessage,
  DisplayItem,
  TeamSnapshot,
  DebugEntry,
  SessionMeta,
  SessionTotals,
} from "./api.js";
