      setSubagentItem(item);
      setSubagentMsgIdx(0);
      setSubagentDetailMsg(null);
      setBodyScrollOffset(0);
      setHeaderScrollOffset(0);
    } else {
      expandedItems.toggle(selectedItem);
      setBodyScrollOffset(0);
    }
  } else if (input === "e") {
    expandedItems.addAll(items.map((_it, i) => i));
    setBodyScrollOffset(0);
